export const vocabularyIndex = vocabularyData.map(({ language, slug, nativeName, flag, speakers, family }) => ({
  language,
  slug,
  nativeName,
  flag,
  speakers,
  family,
}))

export function getVocabularyBySlug(slug: string): LanguageVocabulary | undefined {
  return vocabularyData.find((v) => v.slug === slug)
}
